import java.io.IOException;

public class ImageConverter {

    public void convertImage(String inputFilename, String outputFilename, String format) throws IOException, InterruptedException {
        String[] cmd = {"convert", inputFilename, outputFilename + "." + format};
        Process process = Runtime.getRuntime().exec(cmd);
        int exitCode = process.waitFor();
        
        if (exitCode != 0) {
            throw new RuntimeException("Image conversion failed with exit code " + exitCode);
        }
    }

    public static void main(String[] args) {
        ImageConverter converter = new ImageConverter();
        try {
            converter.convertImage("input.jpg", "output", "png");
            System.out.println("Image converted successfully.");
        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }
}